Steps:
--- SEED (ADMIN) ---
[AUTH role=ADMIN]
[REST-OP seed_msg]
POST /api/push-message
Content-Type: application/json
Body: {"topic": "AGENT-TEST-push011", "shortMessage": "AGENT-TEST-push011-body", "status": "Sent", "startDate": "2026-01-01T00:00:00Z", "memberIds": ["{{ORG_USER_ID}}"]}
[REST-EXEC seed_msg]
--- READ (ORG_USER xAPI) ---
[AUTH role=ORG_USER]
[GQL-OP get_messages]
  query GetPushMessages($first: Int, $unreadOnly: Boolean, $keyword: String, $sort: String) {
    pushMessages(first: $first, unreadOnly: $unreadOnly, keyword: $keyword, sort: $sort) {
      totalCount
      pageInfo { endCursor hasNextPage }
      items {
        id
        shortMessage
        isRead
        createdDate
      }
    }
  }
[GQL-VARS get_messages] {"first": 20, "unreadOnly": false}
[GQL-EXEC get_messages]
[GQL-CAPTURE get_messages.data.pushMessages.items.0.id → FIRST_MSG_ID]

--- SEED (ADMIN) ---
[AUTH role=ADMIN]
[REST-OP seed_msg]
POST /api/push-message
Content-Type: application/json
Body: {"topic": "AGENT-TEST-push012", "shortMessage": "AGENT-TEST-push012-body", "status": "Sent", "startDate": "2026-01-01T00:00:00Z", "memberIds": ["{{ORG_USER_ID}}"]}
[REST-EXEC seed_msg]
--- READ STATE (ORG_USER xAPI) ---
[AUTH role=ORG_USER]
[GQL-OP force_unread]
  mutation { markAllPushMessagesUnread }
[GQL-EXEC force_unread]
[GQL-OP probe_before]
  query { pushMessages(first: 5, unreadOnly: true) { items { id isRead } } }
[GQL-EXEC probe_before]
[GQL-CAPTURE probe_before.data.pushMessages.items.0.id → MSG_ID]
[GQL-OP mark_read]
  mutation MarkRead($command: InputMarkPushMessageReadType!) {
    markPushMessageRead(command: $command)
  }
[GQL-VARS mark_read] {"command": {"messageId": "{{MSG_ID}}"}}
[GQL-EXEC mark_read]
[GQL-OP read_back]
  query ReadBack($first: Int) {
    pushMessages(first: $first, unreadOnly: false) {
      items { id isRead }
    }
  }
[GQL-VARS read_back] {"first": 50}
[GQL-EXEC read_back]
